import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"How do I enroll an authenticator app?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/account/enroll-authenticator.md","filePath":"guide/recipes/account/enroll-authenticator.md","lastUpdated":1779094756000}'),n={name:"guide/recipes/account/enroll-authenticator.md"};function i(l,e,s,c,d,u){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="how-do-i-enroll-an-authenticator-app" tabindex="-1">How do I enroll an authenticator app? <a class="header-anchor" href="#how-do-i-enroll-an-authenticator-app" aria-label="Permalink to &quot;How do I enroll an authenticator app?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p>Anyone — this is on <strong>your own account</strong></p></div><p>Authenticator apps (Google Authenticator, 1Password, Authy, etc.) generate a 6-digit code that rotates every 30 seconds. It&#39;s the most common second factor.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Account</strong> in the sidebar.</li><li>Scroll to <strong>Security → Authentication Methods</strong>.</li><li>Click <strong>Set up Authenticator App</strong>.</li><li>A modal shows a QR code and a manual secret string. Open your authenticator app and either: <ul><li>Scan the QR code (easiest), or</li><li>Add an entry manually and paste the secret.</li></ul></li><li>Your app starts generating 6-digit codes.</li><li>Type the current code in the <strong>Verification Code</strong> field and click <strong>Verify</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>Your authenticator is enrolled. Next sign-in, after your password or SSO, you&#39;ll be prompted for a 6-digit code.</p><div class="warning custom-block"><p class="custom-block-title">Save your backup codes</p><p>The modal also gives you one-time backup codes. Save them in a password manager — you&#39;ll need them if you lose your phone.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./add-passkey">How do I add a passkey?</a></li><li><a href="./reset-mfa">How do I reset my MFA?</a></li></ul>',10)])])}const m=t(n,[["render",i]]);export{h as __pageData,m as default};
